package com.baize.flux.engine;
import com.baize.flux.api.table.*; import com.baize.flux.planner.PipelinePlan;
/** Executes splits sequentially in one process and one thread. */
public final class BatchPipelineExecutor { public JobResult execute(PipelinePlan plan) { long rows=0; var writer=plan.sink().createWriter(); try { writer.open(); for(var split:plan.source().planSplits()) try(var reader=plan.source().createReader(split)){ reader.open(); while(true){var result=reader.poll(plan.batchSize()); var batch=result.batch(); if(batch!=null && batch.size()>0){for(var t:plan.transforms())batch=t.transform(batch); rows+=writer.write(batch);} if(result.finished())break; }} writer.flush(); return JobResult.succeeded(rows); } catch(Exception e){writer.abort(e); throw new JobExecutionException("Pipeline failed",e);} finally {try{writer.close();}catch(Exception ignored){}} } public record JobResult(long rowsWritten){static JobResult succeeded(long n){return new JobResult(n);}} public static final class JobExecutionException extends RuntimeException {JobExecutionException(String m,Throwable c){super(m,c);}} }
